class Solution {
public:
    string shortestPalindrome(string s) {
        if (s.empty()) return s;
        string rs = s;
        reverse(rs.begin(), rs.end());
        string t = s + '#' + rs;
        vector<int> fail = computeFailure(t);
        int l = fail.back();
        string add = s.substr(l);
        reverse(add.begin(), add.end());
        return add + s;
    }

private:
    vector<int> computeFailure(const string &t) {
        int n = t.size();
        vector<int> fail(n, 0);
        for (int i = 1; i < n; ++i) {
            int j = fail[i-1];
            while (j > 0 && t[i] != t[j]) {
                j = fail[j-1];
            }
            if (t[i] == t[j]) {
                j++;
            }
            fail[i] = j;
        }
        return fail;
    }
};

